from collections import Counter
from itertools import combinations
class Solution:
    def countKSubsequencesWithMaxBeauty(self, s, k):
        MOD = 10 ** 9 + 7
        n = len(s)
        freq = Counter(s)
        best = -1
        cnt = 0
        for combo in combinations(range(n), k):
            chars = [s[i] for i in combo]
            if len(set(chars)) != k:
                continue
            beauty = sum(freq[c] for c in chars)
            if beauty > best:
                best = beauty
                cnt = 1
            elif beauty == best:
                cnt += 1
        return cnt % MOD if best >= 0 else 0

