from collections import Counter
class Solution:
    def countKSubsequencesWithMaxBeauty(self, s, k):
        MOD = 10 ** 9 + 7
        freq = Counter(s)
        freqs = sorted(freq.values(), reverse=True)
        distinct = len(freqs)
        if k > distinct:
            return 0
        N = 30
        fact = [1] * N
        for i in range(1, N):
            fact[i] = fact[i - 1] * i
        def C(a, b):
            if b < 0 or b > a:
                return 0
            return fact[a] // (fact[b] * fact[a - b])
        ans = 1
        i = 0
        remaining = k
        n = len(freqs)
        while i < n and remaining > 0:
            j = i
            while j < n and freqs[j] == freqs[i]:
                j += 1
            group_size = j - i
            val = freqs[i]
            if remaining >= group_size:
                ans = ans * pow(val, group_size, MOD) % MOD
                remaining -= group_size
            else:
                ans = ans * C(group_size, remaining) % MOD
                ans = ans * pow(val, remaining, MOD) % MOD
                remaining = 0
            i = j
        return ans % MOD

