var countKSubsequencesWithMaxBeauty = function(s, k) {
    const MOD = 1000000007n;
    const freqMap = new Map();
    for (const ch of s) freqMap.set(ch, (freqMap.get(ch) || 0) + 1);
    const freqs = Array.from(freqMap.values()).sort((a, b) => b - a);
    const distinct = freqs.length;
    if (k > distinct) return 0;
    const N = 30;
    const fact = new Array(N).fill(1n);
    for (let i = 1; i < N; i++) fact[i] = fact[i - 1] * BigInt(i);
    function C(a, b) {
        if (b < 0 || b > a) return 0n;
        return fact[a] / (fact[b] * fact[a - b]);
    }
    function power(a, b, m) {
        a %= m; if (a < 0n) a += m;
        let res = 1n;
        while (b > 0n) {
            if (b & 1n) res = res * a % m;
            a = a * a % m;
            b >>= 1n;
        }
        return res;
    }
    let ans = 1n;
    let i = 0;
    let remaining = k;
    const n = freqs.length;
    while (i < n && remaining > 0) {
        let j = i;
        while (j < n && freqs[j] === freqs[i]) j++;
        const groupSize = j - i;
        const val = BigInt(freqs[i]);
        if (remaining >= groupSize) {
            ans = ans * power(val, BigInt(groupSize), MOD) % MOD;
            remaining -= groupSize;
        } else {
            ans = ans * (C(groupSize, remaining) % MOD) % MOD;
            ans = ans * power(val, BigInt(remaining), MOD) % MOD;
            remaining = 0;
        }
        i = j;
    }
    return Number(((ans % MOD) + MOD) % MOD);
};
